const {spawn} = require('child_process');
const {existsSync, mkdtempSync, readFileSync} = require('fs');
const {tmpdir} = require('os');
const {join} = require('path');
const home = mkdtempSync(join(tmpdir(), 'codex-mem-repro-'));
const env = {...process.env, HOME: home};
const first = spawn(process.execPath, ['dist/cli.js', 'mcp-server'], {stdio: ['pipe','pipe','pipe'], env});
const started = Date.now();
setTimeout(() => {
  const second = spawn(process.execPath, ['dist/cli.js', 'mcp-server'], {stdio: ['pipe','pipe','pipe'], env});
  first.on('exit', (code, signal) => {
    const lockPath = join(home, '.codex-mem', 'runtime-locks', 'mcp-server.json');
    const deadline = Date.now() + 3000;
    const poll = () => {
      if (existsSync(lockPath)) {
        const lock = JSON.parse(readFileSync(lockPath, 'utf8'));
        console.log(JSON.stringify({scenario:'takeover', first_exit_code:code, first_exit_signal:signal, lock_pid: lock?.pid ?? null, second_pid: second.pid, elapsed_ms: Date.now()-started}));
        second.stdin.end();
        process.exit(lock?.pid === second.pid && [0,1].includes(code) ? 0 : 4);
        return;
      }
      if (Date.now() >= deadline) {
        console.log(JSON.stringify({scenario:'takeover', first_exit_code:code, first_exit_signal:signal, lock_pid: null, second_pid: second.pid, elapsed_ms: Date.now()-started, lock_timeout:true}));
        second.stdin.end();
        process.exit(5);
        return;
      }
      setTimeout(poll, 50);
    };
    poll();
  });
}, 500);
setTimeout(() => {
  try { first.kill('SIGKILL'); } catch {}
  console.log(JSON.stringify({scenario:'takeover', timeout:true, elapsed_ms: Date.now()-started}));
  process.exit(2);
}, 7000);
